/**
 * generate-llms-full.mjs
 * ======================
 * Generates client/public/llms-full.txt — a plain-text, markdown-convention
 * dump of all knowledge base articles and FAQ content, per the llmstxt.org spec.
 *
 * Ordering: newest lastUpdated first, then newest date first, then alpha by title.
 * Content source: scripts/article-data-full.json (generated by extract-article-content.mjs)
 * FAQ source: client/src/pages/FAQ.tsx (parsed via regex)
 *
 * Run: node scripts/generate-llms-full.mjs
 * Output: client/public/llms-full.txt
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.resolve(__dirname, "..");

const articleDataPath = path.resolve(__dirname, "article-data-full.json");
const faqTsxPath = path.resolve(projectRoot, "client/src/pages/FrequentlyAskedQuestions.tsx");
const outputPath = path.resolve(projectRoot, "client/public/llms-full.txt");

// ─── Helpers ────────────────────────────────────────────────────────────────

/**
 * Strip HTML tags from a string, preserving text content.
 * Also converts common HTML entities.
 */
function stripHtml(str) {
  return str
    .replace(/<[^>]+>/g, "")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ")
    .replace(/&#x27;/g, "'")
    .replace(/&#x2F;/g, "/")
    .replace(/\u2013/g, "–")
    .replace(/\u2014/g, "—")
    .replace(/\u2018/g, "'")
    .replace(/\u2019/g, "'")
    .replace(/\u201C/g, '"')
    .replace(/\u201D/g, '"')
    .replace(/\u02BB/g, "'");
}

/**
 * Convert image markdown to [image: alt text], drop bare image tags.
 * Keep all other markdown intact.
 */
function processMarkdown(content) {
  // Replace ![alt](url) with [image: alt]
  let out = content.replace(/!\[([^\]]*)\]\([^)]*\)/g, (_, alt) =>
    alt ? `[image: ${alt}]` : ""
  );
  // Strip any remaining HTML tags
  out = stripHtml(out);
  // Normalize excessive blank lines (max 2)
  out = out.replace(/\n{3,}/g, "\n\n");
  return out.trim();
}

/**
 * Parse a date string like "March 2026", "April 2026", "2026-04-26" into
 * a sortable ISO-like string for comparison.
 */
function parseDate(dateStr) {
  if (!dateStr) return "0000-00-00";
  // Already ISO format
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) return dateStr;
  // "Month YYYY" format
  const monthMap = {
    January: "01", February: "02", March: "03", April: "04",
    May: "05", June: "06", July: "07", August: "08",
    September: "09", October: "10", November: "11", December: "12",
  };
  const m = dateStr.match(/^(\w+)\s+(\d{4})$/);
  if (m) {
    const month = monthMap[m[1]] || "01";
    return `${m[2]}-${month}-01`;
  }
  return "0000-00-00";
}

/**
 * Format a date for display: "2026-04-26" → "April 26, 2026"
 * "March 2026" → "March 2026"
 */
function formatDate(dateStr) {
  if (!dateStr) return "";
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    const d = new Date(dateStr + "T12:00:00Z");
    return d.toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" });
  }
  return dateStr;
}

/**
 * Extract FAQ categories and items from FAQ.tsx source using regex.
 * Returns array of { category, items: [{question, answer}] }
 */
function extractFaqFromTsx() {
  const src = fs.readFileSync(faqTsxPath, "utf-8");

  // Find the FAQ_CATEGORIES array
  const startMarker = "const FAQ_CATEGORIES: FAQCategory[] = [";
  const startIdx = src.indexOf(startMarker);
  if (startIdx === -1) {
    console.warn("Could not find FAQ_CATEGORIES in FAQ.tsx");
    return [];
  }

  // Extract the array content by counting brackets
  let depth = 0;
  let arrayStart = src.indexOf("[", startIdx + startMarker.length - 1);
  let i = arrayStart;
  let arrayEnd = -1;
  while (i < src.length) {
    if (src[i] === "[") depth++;
    else if (src[i] === "]") {
      depth--;
      if (depth === 0) { arrayEnd = i; break; }
    }
    i++;
  }
  if (arrayEnd === -1) {
    console.warn("Could not find end of FAQ_CATEGORIES array");
    return [];
  }

  const arrayContent = src.substring(arrayStart, arrayEnd + 1);
  const categories = [];

  // Extract each category block
  const catTitleRe = /title:\s*"([^"]+)"/g;
  const catIdRe = /id:\s*"([^"]+)"/g;

  // Find category boundaries by finding title: matches
  const titleMatches = [...arrayContent.matchAll(/\{\s*\n\s*title:\s*"([^"]+)"/g)];

  for (let ci = 0; ci < titleMatches.length; ci++) {
    const catTitle = titleMatches[ci][1];
    const catStart = titleMatches[ci].index;
    const catEnd = ci + 1 < titleMatches.length ? titleMatches[ci + 1].index : arrayContent.length;
    const catBlock = arrayContent.substring(catStart, catEnd);

    // Extract Q&A pairs
    const items = [];
    const qaRe = /question:\s*"((?:[^"\\]|\\.|[\s\S])*?)",\s*\n\s*answer:\s*"((?:[^"\\]|\\.|[\s\S])*?)"/g;
    let qm;
    while ((qm = qaRe.exec(catBlock)) !== null) {
      const question = qm[1]
        .replace(/\\n/g, "\n")
        .replace(/\\"/g, '"')
        .replace(/\\'/g, "'")
        .replace(/\u02BB/g, "'");
      const answer = qm[2]
        .replace(/\\n/g, "\n")
        .replace(/\\"/g, '"')
        .replace(/\\'/g, "'")
        .replace(/\u02BB/g, "'");
      items.push({ question, answer });
    }

    if (items.length > 0) {
      categories.push({ category: catTitle, items });
    }
  }

  return categories;
}

// ─── Main ────────────────────────────────────────────────────────────────────

function generate() {
  // 1. Load article data
  if (!fs.existsSync(articleDataPath)) {
    console.error(`article-data-full.json not found at ${articleDataPath}`);
    console.error("Run: node scripts/extract-article-content.mjs first");
    process.exit(1);
  }
  const articles = JSON.parse(fs.readFileSync(articleDataPath, "utf-8"));

  // 2. Sort: newest lastUpdated first, then newest date, then alpha title
  const sorted = [...articles].sort((a, b) => {
    const aUpdated = parseDate(a.lastUpdated || a.date);
    const bUpdated = parseDate(b.lastUpdated || b.date);
    if (aUpdated !== bUpdated) return bUpdated.localeCompare(aUpdated);
    const aDate = parseDate(a.date);
    const bDate = parseDate(b.date);
    if (aDate !== bDate) return bDate.localeCompare(aDate);
    return a.title.localeCompare(b.title);
  });

  // 3. Find most recent date for header
  const mostRecentDate = sorted.length > 0
    ? formatDate(sorted[0].lastUpdated || sorted[0].date)
    : "2026";

  // 4. Extract FAQ
  const faqCategories = extractFaqFromTsx();

  // 5. Build output
  const lines = [];

  // ── File header ──
  lines.push("# RealityCents — Full Knowledge Base");
  lines.push("");
  lines.push("> Hawaii mortgage education and VA loan expertise by Jay Miller, NMLS #657301, CMG Home Loans.");
  lines.push("> Plain-text dump of all knowledge base articles, guide chapters, and Hawaii-specific topic guides.");
  lines.push("> Optimized for AI ingestion. For the curated index, see https://realitycents.com/llms.txt");
  lines.push(">");
  lines.push(`> Last updated: ${mostRecentDate}`);
  lines.push("> Source: https://realitycents.com/llms-full.txt");
  lines.push("> Author: Jay Miller, Sales Manager & Mortgage Loan Consultant, CMG Home Loans");
  lines.push("> Contact: jaym@cmghomeloans.com | 808-429-0811");
  lines.push("> Office: 500 Ala Moana Blvd, Suite 6-200, Honolulu, HI 96813");
  lines.push("");

  // ── Knowledge Base Articles ──
  for (const article of sorted) {
    const url = `https://realitycents.com/knowledge-base/${article.slug}`;
    const published = formatDate(article.date);
    const updated = article.lastUpdated ? formatDate(article.lastUpdated) : published;
    const body = processMarkdown(article.content || "");

    lines.push("---");
    lines.push("");
    lines.push(`## ${article.title}`);
    lines.push(`URL: ${url}`);
    lines.push(`Author: Jay Miller, NMLS #657301, CMG Home Loans`);
    lines.push(`Published: ${published}`);
    lines.push(`Last updated: ${updated}`);
    lines.push("");
    lines.push(body);
    lines.push("");
  }

  // ── FAQ Section ──
  if (faqCategories.length > 0) {
    lines.push("---");
    lines.push("");
    lines.push("## Frequently Asked Questions");
    lines.push("URL: https://realitycents.com/faq");
    lines.push("Author: Jay Miller, NMLS #657301, CMG Home Loans");
    lines.push("Published: January 2026");
    lines.push("Last updated: April 2026");
    lines.push("");

    for (const cat of faqCategories) {
      lines.push(`### ${cat.category}`);
      lines.push("");
      for (const item of cat.items) {
        lines.push(`**Q: ${stripHtml(item.question)}**`);
        lines.push("");
        lines.push(`A: ${stripHtml(item.answer)}`);
        lines.push("");
      }
    }
  }

  // ── VA Approved Condos Directory ──
  lines.push("---");
  lines.push("");
  lines.push("## VA-Approved Condos on Oahu");
  lines.push("URL: https://realitycents.com/va-approved-condos-oahu");
  lines.push("Author: Jay Miller, NMLS #657301, CMG Home Loans");
  lines.push("Published: May 2026");
  lines.push("Last updated: May 2026");
  lines.push("");
  lines.push("Searchable directory of all VA-approved condo projects on Oahu, Hawaii. Data sourced from the VA LGY Hub (lgy.va.gov/lgyhub/condo-report).");
  lines.push("");
  try {
    const condoDataPath = path.resolve(projectRoot, "client/src/data/va-approved-condos-oahu.json");
    const condoData = JSON.parse(fs.readFileSync(condoDataPath, "utf-8"));
    lines.push(`Total VA-approved condos on Oahu: ${condoData.totalApproved}`);
    lines.push(`- Accepted Without Conditions: ${condoData.withoutConditions}`);
    lines.push(`- Accepted With Conditions: ${condoData.withConditions}`);
    lines.push(`- Last updated: ${condoData.lastUpdated}`);
    lines.push("");
    lines.push("### What VA Condo Approval Means");
    lines.push("");
    lines.push("VA condo approval means the Department of Veterans Affairs has reviewed a condominium project's legal documents, financials, and HOA governance and determined it meets VA lending standards. Without this approval, VA-eligible buyers cannot use their VA loan benefit to purchase a unit in that project.");
    lines.push("");
    lines.push("### Accepted Without Conditions vs. Accepted With Conditions");
    lines.push("");
    lines.push("Accepted Without Conditions means the project fully meets all VA requirements with no additional stipulations. Accepted With Conditions means the project is approved but the VA identified items that need to be addressed or monitored \u2014 such as pending litigation, reserve fund shortfalls, or investor concentration ratios. Both statuses allow VA financing.");
    lines.push("");
    lines.push("### What If Your Condo Isn't on the List?");
    lines.push("");
    lines.push("You can request a Single Unit Approval (Spot Approval) where the VA reviews just the individual unit (1-2 weeks), or the HOA/seller can submit a full project approval application (4-8 weeks) that approves the entire building for all future VA buyers.");
    lines.push("");
    lines.push("### Oahu Neighborhoods with VA-Approved Condos");
    lines.push("");
    const neighborhoodCounts = {};
    condoData.condos.forEach(c => {
      neighborhoodCounts[c.neighborhood] = (neighborhoodCounts[c.neighborhood] || 0) + 1;
    });
    Object.entries(neighborhoodCounts).sort((a, b) => b[1] - a[1]).forEach(([name, count]) => {
      lines.push(`- ${name}: ${count} projects`);
    });
    lines.push("");
  } catch (e) {
    console.warn("[llms-full] Could not load VA condo data:", e.message);
  }

  // ── Military Installation Hub Pages ──
  const BASE_PAGES = [
    { slug: "va-loan-schofield-barracks", title: "VA Loan Guide for Schofield Barracks", installation: "Schofield Barracks", branch: "U.S. Army, 25th Infantry Division" },
    { slug: "va-loan-pearl-harbor-hickam", title: "VA Loan Guide for Pearl Harbor-Hickam", installation: "Joint Base Pearl Harbor-Hickam", branch: "U.S. Navy / Air Force" },
    { slug: "va-loan-kaneohe-mcbh", title: "VA Loan Guide for MCBH Kaneohe Bay", installation: "Marine Corps Base Hawaii", branch: "U.S. Marine Corps" },
    { slug: "va-loan-fort-shafter", title: "VA Loan Guide for Fort Shafter", installation: "Fort Shafter", branch: "U.S. Army, USARPAC Headquarters" },
    { slug: "va-loan-tripler", title: "VA Loan Guide for Tripler Army Medical Center", installation: "Tripler AMC", branch: "U.S. Army Medical" },
  ];
  for (const basePage of BASE_PAGES) {
    lines.push("---");
    lines.push("");
    lines.push(`## ${basePage.title}`);
    lines.push(`URL: https://realitycents.com/${basePage.slug}`);
    lines.push(`Author: Jay Miller, NMLS #657301, CMG Home Loans`);
    lines.push(`Published: 2026-05-12`);
    lines.push(`Last updated: 2026-05-12`);
    lines.push("");
    lines.push(`Complete VA loan guide for military families PCS'ing to ${basePage.installation} (${basePage.branch}). Includes 2026 BAH rates for Honolulu County, payment scenarios by rank (E-5 through O-6, plus W-1 through W-5), best neighborhoods with commute times and price ranges, VA condo considerations, and FAQs specific to the installation. All calculations use 5.75% rate, VA funding fee financed, Honolulu County property tax 0.31%.`);
    lines.push("");
    lines.push(`### 2026 BAH Rates (Honolulu County)`);
    lines.push(`- E-5: $3,663 w/dep, $2,856 w/o dep`);
    lines.push(`- E-6: $3,861 w/dep, $3,036 w/o dep`);
    lines.push(`- E-7: $4,098 w/dep, $3,348 w/o dep`);
    lines.push(`- E-8: $4,302 w/dep, $3,720 w/o dep`);
    lines.push(`- E-9: $4,518 w/dep, $3,783 w/o dep`);
    lines.push(`- W-1: $3,930 w/dep, $3,222 w/o dep`);
    lines.push(`- W-2: $4,182 w/dep, $3,717 w/o dep`);
    lines.push(`- W-3: $4,434 w/dep, $3,795 w/o dep`);
    lines.push(`- W-4: $4,551 w/dep, $3,951 w/o dep`);
    lines.push(`- W-5: $4,692 w/dep, $4,146 w/o dep`);
    lines.push(`- O-1: $3,702 w/dep, $2,997 w/o dep`);
    lines.push(`- O-2: $3,909 w/dep, $3,555 w/o dep`);
    lines.push(`- O-3: $4,434 w/dep, $3,819 w/o dep`);
    lines.push(`- O-4: $4,719 w/dep, $4,110 w/o dep`);
    lines.push(`- O-5: $4,959 w/dep, $4,224 w/o dep`);
    lines.push(`- O-6: $5,001 w/dep, $4,413 w/o dep`);
    lines.push("");
    lines.push(`### Key Facts`);
    lines.push(`- No VA loan limit with full entitlement ($0 down at any price)`);
    lines.push(`- $1,249,125 conforming limit only applies with reduced entitlement`);
    lines.push(`- BAH is tax-free income, helping VA buyers qualify for more house`);
    lines.push(`- VA appraisals on Oahu: 7-10 business days (ordered after inspection period)`);
    lines.push(`- Typical close time: 30-45 days`);
    lines.push("");
  }

  // ── Loan Comparison Calculator ──
  lines.push("---");
  lines.push("");
  lines.push("## Loan Comparison Calculator");
  lines.push("URL: https://realitycents.com/loan-compare");
  lines.push("");
  lines.push("Interactive tool for comparing up to 3 loan scenarios side by side. Supports VA, FHA, and conventional loans with full payment breakdown (P&I, property tax, insurance, HOA, mortgage insurance), closing costs, prepaids, APR calculation, amortization schedule, and total cost over a configurable time horizon. Features shareable links (lz-string compressed URL parameters) so lenders can pre-fill scenarios and send to clients. Print-friendly layout with Jay Miller's branding. Hawaii-specific defaults: Honolulu County 0.35%, Maui 0.55%, Kauai 0.59%, Hawaii County 0.99% property tax rates. VA funding fee auto-calculated (2.15% first use, 3.3% subsequent, reduced with down payment, exempt for disabled veterans). FHA UFMIP (1.75%) and monthly MIP included. Conventional PMI calculated based on LTV.");
  lines.push("");

  // ── Closing block ──
  lines.push("---");
  lines.push("");
  lines.push("## About RealityCents");
  lines.push("");
  lines.push(
    "RealityCents.com is an educational mortgage resource for Hawaii homebuyers, refinancers, and military families. " +
    "All content is authored by Jay Miller, Sales Manager and Mortgage Loan Consultant at CMG Home Loans (NMLS #657301), " +
    "a US Army veteran with 25 years of Hawaii mortgage experience. The site specializes in VA loans, conventional loans, " +
    "FHA loans, and Hawaii condo financing. All guidance reflects Hawaii-specific rules including condo warrantability " +
    "requirements, leasehold property considerations, PC-9 termite inspection mandates, and Honolulu County property tax exemptions."
  );
  lines.push("");
  lines.push(
    "NMLS Consumer Access verification: https://www.nmlsconsumeraccess.org/EntityDetails.aspx/INDIVIDUAL/657301"
  );
  lines.push("");
  lines.push("End of llms-full.txt");
  lines.push("");

  // 6. Join and write
  const output = lines.join("\n");

  // 7. Validate: no HTML tags
  const htmlTagMatch = output.match(/<[a-zA-Z][^>]*>/);
  if (htmlTagMatch) {
    console.error(`[llms-full] VALIDATION FAILED: HTML tag found: ${htmlTagMatch[0]}`);
    process.exit(1);
  }

  // 8. Validate: file size > 50KB
  const byteSize = Buffer.byteLength(output, "utf-8");
  if (byteSize < 50 * 1024) {
    console.error(`[llms-full] VALIDATION FAILED: File too small (${byteSize} bytes, expected > 51200)`);
    process.exit(1);
  }

  // 9. Write output
  fs.mkdirSync(path.dirname(outputPath), { recursive: true });
  fs.writeFileSync(outputPath, output, "utf-8");

  const kb = (byteSize / 1024).toFixed(1);
  console.log(`[llms-full] Generated llms-full.txt — ${sorted.length} articles, ${faqCategories.reduce((s, c) => s + c.items.length, 0)} FAQs, ${kb} KB`);
  console.log(`[llms-full] Output: ${outputPath}`);
}

generate();
